<style>
  :root{
    --bg: #F6F9FD;
    --bg-soft: #EEF3FA;
    --surface: rgba(255,255,255,0.72);
    --surface-solid: #FFFFFF;
    --border: rgba(16,23,40,0.09);
    --border-strong: rgba(16,23,40,0.16);
    --ink-1: #0F1728;
    --ink-2: #47526B;
    --ink-3: #8996B0;
    --blue: #2F6FED;
    --violet: #7C3AED;
    --cyan: #0891B2;
  }
  *{ box-sizing:border-box; }
  html,body{ height:100%; }
  body{
    background: var(--bg);
    color: var(--ink-1);
    font-family:'Inter', sans-serif;
    position:relative;
    overflow:hidden; /* no whole-page scroll: nav drives which panel shows */
    display:flex; flex-direction:column;
  }
  h1,h2,h3,h4,.display{ font-family:'Plus Jakarta Sans', sans-serif; }
  .mono{ font-family:'JetBrains Mono', monospace; }
  ::selection{ background: rgba(124,58,237,0.18); color:var(--ink-1); }
  ::-webkit-scrollbar{ width:8px; height:8px; }
  ::-webkit-scrollbar-track{ background:transparent; }
  ::-webkit-scrollbar-thumb{ background:linear-gradient(var(--blue),var(--violet)); border-radius:10px; }
  @media (prefers-reduced-motion: reduce){
    *{ animation-duration:0.01ms !important; animation-iteration-count:1 !important; transition-duration:0.01ms !important; }
  }

  /* ---------- Ambient background ---------- */
  .bg-grid{
    position:fixed; inset:0; z-index:0; pointer-events:none;
    background-image:
      linear-gradient(rgba(16,23,40,0.035) 1px, transparent 1px),
      linear-gradient(90deg, rgba(16,23,40,0.035) 1px, transparent 1px);
    background-size:52px 52px;
    mask-image: radial-gradient(ellipse 90% 70% at 50% 0%, black 20%, transparent 78%);
  }
  .blob{ position:fixed; border-radius:50%; filter:blur(100px); pointer-events:none; z-index:0; opacity:0.45; will-change:transform; }
  .blob-1{ width:560px; height:560px; background:radial-gradient(circle, #9DBBFB, transparent 70%); top:-200px; left:-140px; animation:float1 24s ease-in-out infinite; }
  .blob-2{ width:520px; height:520px; background:radial-gradient(circle, #C9B4F9, transparent 70%); top:120px; right:-180px; animation:float2 27s ease-in-out infinite; }
  .blob-3{ width:460px; height:460px; background:radial-gradient(circle, #9EDCE8, transparent 70%); bottom:-160px; left:30%; opacity:0.35; animation:float3 30s ease-in-out infinite; }
  @keyframes float1{ 0%,100%{ transform:translate(0,0) scale(1);} 50%{ transform:translate(50px,60px) scale(1.06);} }
  @keyframes float2{ 0%,100%{ transform:translate(0,0) scale(1);} 50%{ transform:translate(-60px,50px) scale(0.96);} }
  @keyframes float3{ 0%,100%{ transform:translate(0,0) scale(1);} 50%{ transform:translate(30px,-40px) scale(1.08);} }
  #particles{ position:fixed; inset:0; z-index:0; pointer-events:none; opacity:0.5; }
  .cursor-glow{
    position:fixed; width:460px; height:460px; border-radius:50%; pointer-events:none; z-index:1;
    background:radial-gradient(circle, rgba(124,58,237,0.10), rgba(47,111,237,0.05) 45%, transparent 70%);
    transform:translate(-50%,-50%); will-change:transform;
  }

  header, main, footer{ position:relative; z-index:2; }

  /* ---------- Glass ---------- */
  .glass{ background:var(--surface); border:1px solid var(--border); backdrop-filter:blur(16px); -webkit-backdrop-filter:blur(16px); }
  .glass-card{
    background:linear-gradient(180deg, rgba(255,255,255,0.9), rgba(255,255,255,0.62));
    border:1px solid var(--border);
    backdrop-filter:blur(14px); -webkit-backdrop-filter:blur(14px);
    box-shadow:0 1px 2px rgba(16,23,40,0.04);
    transition:transform 0.35s cubic-bezier(.2,.8,.2,1), border-color 0.35s ease, box-shadow 0.35s ease;
  }
  .glass-card:hover{
    transform:translateY(-4px);
    border-color:rgba(124,58,237,0.35);
    box-shadow:0 20px 40px -18px rgba(47,111,237,0.28), 0 0 0 1px rgba(124,58,237,0.12);
  }
  .grad-border{ position:relative; }
  .grad-border::before{
    content:''; position:absolute; inset:0; border-radius:inherit; padding:1px;
    background:linear-gradient(135deg, rgba(47,111,237,0.55), rgba(124,58,237,0.1) 40%, rgba(124,58,237,0.55));
    -webkit-mask:linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);
    -webkit-mask-composite: xor; mask-composite: exclude;
    opacity:0; transition:opacity 0.35s ease; pointer-events:none;
  }
  .glass-card:hover .grad-border::before{ opacity:1; }

  /* ---------- Buttons ---------- */
  .btn-glow{
    position:relative; overflow:hidden;
    background:linear-gradient(135deg, var(--blue), var(--violet));
    box-shadow:0 8px 24px -8px rgba(47,111,237,0.5);
    transition:box-shadow 0.35s ease, transform 0.3s ease;
  }
  .btn-glow:hover{ box-shadow:0 12px 34px -6px rgba(124,58,237,0.55); transform:translateY(-2px); }
  .btn-ghost{ border:1px solid var(--border-strong); background:rgba(255,255,255,0.6); color:var(--ink-1); transition:all 0.3s ease; }
  .btn-ghost:hover{ border-color:rgba(47,111,237,0.4); background:#fff; }

  .text-grad{
    background:linear-gradient(135deg, var(--blue) 10%, var(--violet) 55%, var(--cyan) 100%);
    -webkit-background-clip:text; background-clip:text; color:transparent;
    background-size:200% auto; animation:shine 7s linear infinite;
  }
  @keyframes shine{ to{ background-position:200% center; } }

  /* ---------- Layout shell: header + panel area + footer bar, no page scroll ---------- */
  #navbar{ flex:0 0 auto; }
  #panelArea{ flex:1 1 auto; position:relative; min-height:0; }
  .panel{
    position:absolute; inset:0;
    display:none;
    opacity:0; transform:translateY(10px);
    overflow-y:auto; overflow-x:hidden;
    padding:1.75rem 1.5rem 1.25rem;
  }
  .panel.active{ display:block; animation:panelIn 0.5s cubic-bezier(.2,.8,.2,1) forwards; }
  @keyframes panelIn{ from{ opacity:0; transform:translateY(14px);} to{ opacity:1; transform:translateY(0);} }
  #footerBar{ flex:0 0 auto; }

  .nav-link{ position:relative; color:var(--ink-2); transition:color 0.3s ease; cursor:pointer; }
  .nav-link::after{
    content:''; position:absolute; left:0; bottom:-4px; width:0; height:2px; border-radius:2px;
    background:linear-gradient(90deg,var(--blue),var(--violet)); transition:width 0.3s ease;
  }
  .nav-link:hover{ color:var(--ink-1); }
  .nav-link.active{ color:var(--ink-1); }
  .nav-link.active::after{ width:100%; }

  .float-dash{ animation:floatY 6s ease-in-out infinite; }
  @keyframes floatY{ 0%,100%{ transform:translateY(0) rotate(0.2deg);} 50%{ transform:translateY(-12px) rotate(-0.2deg);} }
  .float-chip{ animation:floatY2 5s ease-in-out infinite; }
  @keyframes floatY2{ 0%,100%{ transform:translateY(0);} 50%{ transform:translateY(-8px);} }
  .pulse-dot{ animation:pulseDot 2s ease-in-out infinite; }
  @keyframes pulseDot{ 0%,100%{ opacity:1; transform:scale(1);} 50%{ opacity:0.45; transform:scale(0.8);} }

  .bar{ transform-origin:bottom; transform:scaleY(0); transition:transform 0.9s cubic-bezier(.2,.8,.2,1); }
  .panel.active .bar{ transform:scaleY(1); }
  .line-path{ stroke-dasharray:600; stroke-dashoffset:600; transition:stroke-dashoffset 1.3s cubic-bezier(.2,.7,.2,1); }
  .panel.active .line-path{ stroke-dashoffset:0; }
  .ring-fill{ stroke-dasharray:283; stroke-dashoffset:283; transition:stroke-dashoffset 1.2s cubic-bezier(.2,.7,.2,1); }
  .panel.active .ring-fill{ stroke-dashoffset:var(--ring-offset,80); }

  .marquee-track{ display:flex; gap:3.5rem; animation:marquee 26s linear infinite; width:max-content; }
  @keyframes marquee{ from{ transform:translateX(0);} to{ transform:translateX(-50%);} }
  .fade-edge{ mask-image:linear-gradient(to right, transparent, black 6%, black 94%, transparent); }

  .pricing-pro{ background:linear-gradient(180deg, rgba(47,111,237,0.09), rgba(124,58,237,0.05)); border:1px solid rgba(124,58,237,0.32); }

  a:focus-visible, button:focus-visible{ outline:2px solid var(--cyan); outline-offset:3px; border-radius:6px; }
  .eyebrow{ letter-spacing:0.14em; }

  .logo-img{ width:38px; height:38px; border-radius:10px; object-fit:cover; box-shadow:0 4px 14px -4px rgba(47,111,237,0.5); }
</style>
</head>
