              <input type="text" placeholder="Your name" class="w-full rounded-xl px-4 py-2.5 text-sm outline-none" style="background:var(--bg-soft); border:1px solid var(--border)">
            </div>
            <div>
              <label class="text-xs text-[var(--ink-3)] mb-1.5 block">Work email</label>
              <input type="email" placeholder="you@company.com" class="w-full rounded-xl px-4 py-2.5 text-sm outline-none" style="background:var(--bg-soft); border:1px solid var(--border)">
            </div>
          </div>
          <div class="mb-4">
            <label class="text-xs text-[var(--ink-3)] mb-1.5 block">Company</label>
            <input type="text" placeholder="Company name" class="w-full rounded-xl px-4 py-2.5 text-sm outline-none" style="background:var(--bg-soft); border:1px solid var(--border)">
          </div>
          <div class="mb-5">
            <label class="text-xs text-[var(--ink-3)] mb-1.5 block">Message</label>
            <textarea rows="3" placeholder="Tell us what you're looking to solve" class="w-full rounded-xl px-4 py-2.5 text-sm outline-none resize-none" style="background:var(--bg-soft); border:1px solid var(--border)"></textarea>
          </div>
          <button type="button" class="btn-glow px-6 py-3 rounded-xl font-semibold text-white flex items-center gap-2">Schedule Demo <i data-lucide="arrow-right" class="w-4 h-4"></i></button>
        </div>
        <div class="lg:col-span-2 flex flex-col gap-4">
          <div class="glass-card rounded-2xl p-5 flex items-center gap-4">
            <div class="w-10 h-10 rounded-xl bg-gradient-to-br from-[var(--blue)] to-[var(--violet)] flex items-center justify-center"><i data-lucide="mail" class="w-4 h-4 text-white"></i></div>
            <div><div class="text-sm font-semibold">Email</div><div class="text-xs text-[var(--ink-3)]">hello@raptor.io</div></div>
          </div>
          <div class="glass-card rounded-2xl p-5 flex items-center gap-4">
            <div class="w-10 h-10 rounded-xl bg-gradient-to-br from-[var(--violet)] to-[var(--cyan)] flex items-center justify-center"><i data-lucide="phone" class="w-4 h-4 text-white"></i></div>
            <div><div class="text-sm font-semibold">Phone</div><div class="text-xs text-[var(--ink-3)]">+91 40 4567 8900</div></div>
          </div>
          <div class="glass-card rounded-2xl p-5 flex items-center gap-4">
            <div class="w-10 h-10 rounded-xl bg-gradient-to-br from-[var(--cyan)] to-[var(--blue)] flex items-center justify-center"><i data-lucide="map-pin" class="w-4 h-4 text-white"></i></div>
            <div><div class="text-sm font-semibold">Office</div><div class="text-xs text-[var(--ink-3)]">HITEC City, Hyderabad, Telangana</div></div>
          </div>
        </div>
      </div>
    </div>
  </section>

</main>

<!-- ============ PERSISTENT FOOTER BAR ============ -->
<footer id="footerBar" class="glass border-t" style="border-color:var(--border)">
  <div class="max-w-7xl mx-auto px-6 lg:px-8 h-12 flex items-center justify-between text-xs text-[var(--ink-3)]">
    <div class="flex items-center gap-2">
      <img src="data:image/png;base64," alt="Raptor" class="w-5 h-5 rounded-md object-cover">
      <span>© 2026 Raptor. All rights reserved.</span>
    </div>
    <div class="hidden sm:flex items-center gap-5">
      <a href="#" class="hover:text-[var(--ink-1)] transition-colors">Privacy</a>
      <a href="#" class="hover:text-[var(--ink-1)] transition-colors">Terms</a>
      <a href="#" class="hover:text-[var(--ink-1)] transition-colors"><i data-lucide="linkedin" class="w-3.5 h-3.5"></i></a>
      <a href="#" class="hover:text-[var(--ink-1)] transition-colors"><i data-lucide="twitter" class="w-3.5 h-3.5"></i></a>
    </div>
  </div>
</footer>

<script>
  lucide.createIcons();

  // Heatmap cells (deterministic-ish random)
  document.getElementById('heatmap').innerHTML = Array.from({length:35}).map(() => {
    const intensity = Math.random()*0.7+0.08;
    const value = Math.round(intensity * 140);
    return `<div class="aspect-square rounded-sm" title="${value} sessions" style="background:rgba(124,58,237,${intensity.toFixed(2)})"></div>`;
  }).join('');

  // ---------- Tab navigation (no whole-page scroll; switch panels) ----------
  const triggers = document.querySelectorAll('.tab-trigger');
  const panels = document.querySelectorAll('.panel');
  const navLinks = document.querySelectorAll('.nav-link');

  function activateTab(tab){
    panels.forEach(p => p.classList.toggle('active', p.id === 'panel-' + tab));
    navLinks.forEach(n => n.classList.toggle('active', n.dataset.tab === tab));
    const activePanel = document.getElementById('panel-' + tab);
    if (activePanel) activePanel.scrollTop = 0;
    document.getElementById('mobileMenu').classList.add('hidden');
    // re-trigger counters within the shown panel
    activePanel.querySelectorAll('[data-counter]').forEach(el => counterIO.observe(el));
    history.replaceState(null, '', '#' + tab);
  }

  triggers.forEach(t => t.addEventListener('click', () => activateTab(t.dataset.tab)));

  const initial = (location.hash || '#home').replace('#','');
  if ([...panels].some(p => p.id === 'panel-' + initial)) activateTab(initial);

  // Mobile menu
  const menuBtn = document.getElementById('menuBtn');
  const mobileMenu = document.getElementById('mobileMenu');
  menuBtn.addEventListener('click', () => mobileMenu.classList.toggle('hidden'));

  // Cursor glow (desktop only)
  const glow = document.getElementById('cursorGlow');
  if (window.matchMedia('(hover: hover)').matches) {
    window.addEventListener('mousemove', (e) => {
      glow.style.transform = `translate(${e.clientX}px, ${e.clientY}px) translate(-50%,-50%)`;
    }, { passive:true });
  } else { glow.style.display = 'none'; }

  // Animated counters (re-usable across tab switches)
  const counterIO = new IntersectionObserver((entries) => {
    entries.forEach(entry => {
      if (!entry.isIntersecting) return;
      const el = entry.target;
      if (el.dataset.done) return;
      const target = parseFloat(el.dataset.counter);
      const decimals = parseInt(el.dataset.decimal || '0');
      const suffix = el.dataset.suffix || '';
      const duration = 1400;
      const start = performance.now();
      function tick(now) {
        const p = Math.min((now - start) / duration, 1);
        const eased = 1 - Math.pow(1 - p, 3);
        const val = target * eased;
        el.textContent = (decimals ? val.toFixed(decimals) : Math.round(val)) + suffix;
        if (p < 1) requestAnimationFrame(tick); else el.dataset.done = '1';
      }
      requestAnimationFrame(tick);
    });
  }, { threshold: 0.05 });
  document.querySelectorAll('[data-counter]').forEach(el => counterIO.observe(el));

  // Particle network canvas
  const canvas = document.getElementById('particles');
  const ctx = canvas.getContext('2d');
  let particles = [];
  function resize(){ canvas.width = window.innerWidth; canvas.height = window.innerHeight; }
  function initParticles(){
    const count = window.innerWidth < 768 ? 26 : 55;
    particles = Array.from({ length: count }, () => ({
      x: Math.random()*canvas.width, y: Math.random()*canvas.height,
      vx:(Math.random()-0.5)*0.3, vy:(Math.random()-0.5)*0.3, r:Math.random()*1.5+0.5
    }));
  }
  function drawParticles(){
    ctx.clearRect(0,0,canvas.width,canvas.height);
    for (let i=0;i<particles.length;i++){
      const p = particles[i];
      p.x+=p.vx; p.y+=p.vy;
      if (p.x<0||p.x>canvas.width) p.vx*=-1;
      if (p.y<0||p.y>canvas.height) p.vy*=-1;
      ctx.beginPath(); ctx.arc(p.x,p.y,p.r,0,Math.PI*2);
      ctx.fillStyle='rgba(124,58,237,0.4)'; ctx.fill();
      for (let j=i+1;j<particles.length;j++){
        const q = particles[j];
        const dx=p.x-q.x, dy=p.y-q.y, dist=Math.sqrt(dx*dx+dy*dy);
        if (dist<120){
          ctx.beginPath(); ctx.moveTo(p.x,p.y); ctx.lineTo(q.x,q.y);
          ctx.strokeStyle=`rgba(47,111,237,${0.10*(1-dist/120)})`; ctx.lineWidth=1; ctx.stroke();
        }
      }
    }
    requestAnimationFrame(drawParticles);
  }
  resize(); initParticles(); drawParticles();
  window.addEventListener('resize', () => { resize(); initParticles(); }, { passive:true });
</script>
</body>
</html>
